282→/* ═══ MICRO-INTERACTION UTILITIES ═══ */
283→
284→/* Card hover lift effect */
285→.hover-lift {
286→  transition: transform 0.2s ease-out, box-shadow 0.2s ease-out, border-color 0.2s ease-out;
287→}
