305→
306→/* Pulse dot animation (for live indicators) */
307→@keyframes pulseDot {
308→  0%, 100% { opacity: 1; transform: scale(1); }
309→  50% { opacity: 0.5; transform: scale(1.5); }
310→}
311→.pulse-dot {
312→  animation: pulseDot 2s ease-in-out infinite;
