358→@media (prefers-reduced-motion: reduce) {
359→  *,
360→  *::before,
361→  *::after {
362→    animation-duration: 0.01ms !important;
363→    animation-iteration-count: 1 !important;
364→    transition-duration: 0.01ms !important;
365→    scroll-behavior: auto !important;
366→  }
367→
368→  .page-enter,
369→  .animate-in,
370→  .animate-slide-up,
371→  .animate-slide-right,
372→  .animate-fade-up,
373→  .stagger-enter,
374→  .scale-enter {
375→    animation: none !important;
376→    opacity: 1 !important;
377→    transform: none !important;
378→  }
379→
380→  .skeleton-shimmer {
381→    animation: none !important;
382→    background: var(--bg-elevated) !important;
